const { ApolloServer, gql } = require('apollo-server');

const typeDefs = gql`
  type Invoice {
    id: ID!
    invoiceNumber: String!
    clientName: String!
    clientEmail: String!
    amount: Float!
    currency: String!
    status: InvoiceStatus!
    issueDate: String!
    dueDate: String!
    items: [InvoiceItem!]!
    subtotal: Float!
    tax: Float!
    total: Float!
    notes: String
    createdAt: String!
    updatedAt: String!
  }

  type InvoiceItem {
    id: ID!
    description: String!
    quantity: Int!
    unitPrice: Float!
    total: Float!
  }

  enum InvoiceStatus {
    DRAFT
    SENT
    PAID
    OVERDUE
    CANCELLED
  }

  type Query {
    invoice(id: ID!): Invoice
  }
`;

