const resolvers = {
  Query: {
    invoice: (parent, args, context) => {
      const { id } = args;
      
      const invoice = invoicesDatabase.find(inv => inv.id === id);
      
      if (!invoice) {
        return null;
      }
      
      return invoice;
    }
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    return {
      user: req.user
    };
  }
});

server.listen({ port: 4000 }).then(({ url }) => {
  console.log(`Server ready at ${url}`);
});